using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Options with the default reflection-based resolver ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2. TryGetTypeInfo<T>() — probe without throwing
//    Person is resolvable (reflection resolver handles any type):
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? resolved))
    Console.WriteLine($"TryGetTypeInfo<Person> → found ({resolved!.Type.Name})");
else
    Console.WriteLine("TryGetTypeInfo<Person> → not available");

// --- Options locked to a source-gen context that only knows about Person ---
var limited = new JsonSerializerOptions { TypeInfoResolver = LimitedContext.Default };

if (limited.TryGetTypeInfo<Person>(out _))
    Console.WriteLine("TryGetTypeInfo<Person> on limited → found");
else
    Console.WriteLine("TryGetTypeInfo<Person> on limited → not available");

// Order is NOT in the source-gen context, so this should report "not available"
if (limited.TryGetTypeInfo<Order>(out _))
    Console.WriteLine("TryGetTypeInfo<Order>  on limited → found");
else
    Console.WriteLine("TryGetTypeInfo<Order>  on limited → not available");

// --- Types ---
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);

// Source-gen context that only includes Person
[JsonSerializable(typeof(Person))]
public partial class LimitedContext : JsonSerializerContext;

